#!/usr/bin/env python3
"""post_synth_podcast.py — auto-emit brainstorm-podcast.m4a for high-stakes brainstorms.

Closes orchestkit#1886. Signal-fired extra (NOT a numbered phase):
runs after /ork:brainstorm Phase 6 synthesis when:

  composite[recommended] >= 8.0 AND len(approaches) >= 4

Mirrors the audio_podcast trigger from Yonatan-HQ/hq-ext-plugin#194.

Three exit-0 "skip" paths (none are errors):
  - signal absent: composite or options below threshold
  - yg-mcp-core not importable (orchestkit is public, yg-mcp-core is HQ-private)
  - hq-content MCP unreachable

Tool stack (yg-mcp-core>=0.3.0):
  - mcp_core.client.probe("hq-content")
  - mcp_core.client.call_with_polling(start=notebook_create_podcast,
                                       status=notebook_status)
  - urllib (stdlib) — download .m4a

Usage:
  post_synth_podcast.py <session-dir>

  <session-dir> must contain:
    brainstorm-output.json   {recommended, composite, approaches, ...}
    design-doc.md            (synthesized design doc from Phase 6)

Outputs:
  <session-dir>/brainstorm-podcast.m4a               on success
  <session-dir>/brainstorm-podcast.json              handoff JSON

Exit codes:
  0   success, auto-skip per signals, OR MCP/dep unreachable (WARN only)
  1   pre-flight failure (missing args, session dir / required files absent)
  2   podcast generation failed AFTER MCP responded (real error)
"""

import argparse
import json
import os
import sys
import urllib.error
import urllib.request
from pathlib import Path
from typing import Any

COMPOSITE_THRESHOLD = 8.0
APPROACHES_THRESHOLD = 4
# Override at test time via env var.
DEFAULT_MCP_SERVER = os.environ.get("ORK_PODCAST_MCP_SERVER", "hq-content")
PODCAST_TIMEOUT_S = 600.0
PODCAST_POLL_S = 5.0
DOWNLOAD_TIMEOUT_S = 120.0


# ---------------------------------------------------------------------------
# CLI
# ---------------------------------------------------------------------------


def _parse_args(argv: list[str] | None = None) -> argparse.Namespace:
    parser = argparse.ArgumentParser(
        description="Auto-emit brainstorm-podcast.m4a for high-stakes brainstorms.",
    )
    parser.add_argument(
        "session_dir",
        type=Path,
        help="Session directory containing brainstorm-output.json + design-doc.md.",
    )
    return parser.parse_args(argv)


# ---------------------------------------------------------------------------
# signal evaluation (pure)
# ---------------------------------------------------------------------------


def _recommended_composite(brainstorm: dict[str, Any]) -> float | None:
    """Pull composite[recommended] as float, or None if not derivable."""
    recommended = brainstorm.get("recommended")
    composite = brainstorm.get("composite")
    if not isinstance(recommended, str) or not isinstance(composite, dict):
        return None
    value = composite.get(recommended)
    if isinstance(value, (int, float)):
        return float(value)
    return None


def _approaches_count(brainstorm: dict[str, Any]) -> int:
    approaches = brainstorm.get("approaches")
    if isinstance(approaches, list):
        return len(approaches)
    return 0


def evaluate_signal(brainstorm: dict[str, Any]) -> tuple[bool, str]:
    """Return (fires, reason). reason is always populated."""
    composite = _recommended_composite(brainstorm)
    n_approaches = _approaches_count(brainstorm)
    if composite is None:
        return False, "no composite[recommended] available"
    if composite < COMPOSITE_THRESHOLD:
        return False, f"composite={composite:.2f} < {COMPOSITE_THRESHOLD}"
    if n_approaches < APPROACHES_THRESHOLD:
        return False, f"approaches={n_approaches} < {APPROACHES_THRESHOLD}"
    return True, (
        f"composite={composite:.2f} >= {COMPOSITE_THRESHOLD} "
        f"and approaches={n_approaches} >= {APPROACHES_THRESHOLD}"
    )


# ---------------------------------------------------------------------------
# handoff JSON
# ---------------------------------------------------------------------------


def _write_handoff(handoff_path: Path, payload: dict[str, Any]) -> None:
    handoff_path.write_text(json.dumps(payload, indent=2, sort_keys=True), encoding="utf-8")


def _write_skip(handoff_path: Path, reason: str) -> None:
    _write_handoff(handoff_path, {"status": "skipped", "skip_reason": reason})


# ---------------------------------------------------------------------------
# MCP preflight + run
# ---------------------------------------------------------------------------


def _resolve_m4a_url(result: Any) -> str | None:
    """Pull the .m4a URL out of the call_with_polling result.

    The notebook_create_podcast tool's status payload varies — accept any of
    the common shapes (string, or dict with audio_url/m4a_url/url/result).
    """
    if isinstance(result, str):
        return result
    if isinstance(result, dict):
        for key in ("audio_url", "m4a_url", "url", "result"):
            candidate = result.get(key)
            if isinstance(candidate, str):
                return candidate
    return None


def _download(url: str, dest: Path) -> int:
    """Download `url` to `dest`. Returns bytes written. Raises on failure."""
    with urllib.request.urlopen(url, timeout=DOWNLOAD_TIMEOUT_S) as resp:
        data = resp.read()
    dest.write_bytes(data)
    return len(data)


def fire_podcast(
    server: str,
    spec_path: Path,
    design_doc_path: Path,
    out_path: Path,
) -> tuple[str, int]:
    """Start podcast job, poll for completion, download .m4a.

    Returns (m4a_url, bytes_written). Raises on any failure — caller handles
    the typed exceptions from mcp_core.client.
    """
    from mcp_core.client import call_with_polling

    result = call_with_polling(
        server=server,
        start_tool="notebook_create_podcast",
        status_tool="notebook_status",
        args={
            "sources": [str(spec_path), str(design_doc_path)],
            "style": "design-exploration",
        },
        poll_interval=PODCAST_POLL_S,
        timeout=PODCAST_TIMEOUT_S,
    )
    url = _resolve_m4a_url(result)
    if not url:
        raise RuntimeError(f"podcast response had no resolvable URL: {result!r}")
    size = _download(url, out_path)
    if size == 0:
        out_path.unlink(missing_ok=True)
        raise RuntimeError(f"downloaded file is empty: {out_path}")
    return url, size


# ---------------------------------------------------------------------------
# main
# ---------------------------------------------------------------------------


def main(argv: list[str] | None = None) -> int:
    args = _parse_args(argv)
    session_dir: Path = args.session_dir

    if not session_dir.is_dir():
        print(f"post_synth_podcast: session dir not found: {session_dir}", file=sys.stderr)
        return 1

    brainstorm_path = session_dir / "brainstorm-output.json"
    design_doc_path = session_dir / "design-doc.md"
    handoff_path = session_dir / "brainstorm-podcast.json"
    m4a_path = session_dir / "brainstorm-podcast.m4a"

    if not brainstorm_path.is_file():
        print(
            f"post_synth_podcast: brainstorm-output.json missing at {brainstorm_path}",
            file=sys.stderr,
        )
        return 1

    # Signal probe — auto-skip cleanly if predicate fails.
    try:
        brainstorm = json.loads(brainstorm_path.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError) as exc:
        print(
            f"post_synth_podcast: cannot parse {brainstorm_path}: {exc}",
            file=sys.stderr,
        )
        return 1

    fires, reason = evaluate_signal(brainstorm)
    if not fires:
        print(f"post_synth_podcast: auto-skipped — signal absent ({reason})")
        _write_skip(handoff_path, f"signal absent: {reason}")
        return 0

    print(f"post_synth_podcast: signal fired — {reason}")

    if not design_doc_path.is_file():
        print(f"post_synth_podcast: WARN — design-doc.md missing at {design_doc_path}; skipping")
        _write_skip(handoff_path, f"design-doc.md not found at {design_doc_path}")
        return 0

    # MCP preflight — fail-soft on dep miss OR unreachable server.
    try:
        from mcp_core.client import (  # type: ignore[import-not-found]
            McpTimeout,
            McpToolError,
            McpUnreachable,
            probe,
        )
    except ImportError:
        print(
            "post_synth_podcast: WARN — yg-mcp-core not importable; skipping "
            "(install yg-mcp-core>=0.3.0 from pypi.yonyon.ai to enable)"
        )
        _write_skip(handoff_path, "yg-mcp-core not importable")
        return 0

    server = DEFAULT_MCP_SERVER
    if not probe(server):
        print(f"post_synth_podcast: WARN — {server!r} MCP unreachable; skipping")
        _write_skip(handoff_path, f"{server!r} MCP unreachable")
        return 0

    # Fire podcast job.
    print(
        "post_synth_podcast: starting podcast generation "
        "(sources: brainstorm-output.json + design-doc.md)"
    )
    try:
        url, size = fire_podcast(server, brainstorm_path, design_doc_path, m4a_path)
    except (McpUnreachable, McpToolError, McpTimeout) as exc:
        print(f"post_synth_podcast: ERROR — {type(exc).__name__}: {exc}", file=sys.stderr)
        return 2
    except (RuntimeError, urllib.error.URLError, OSError) as exc:
        print(f"post_synth_podcast: ERROR — {exc}", file=sys.stderr)
        return 2

    _write_handoff(
        handoff_path,
        {
            "status": "fired",
            "m4a_path": str(m4a_path),
            "m4a_url": url,
            "size_bytes": size,
        },
    )
    print(f"post_synth_podcast: ✓ wrote {m4a_path} ({size} bytes)")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
